const Q_PHYSICS_2007=[{"id": "objective>Physics>2007>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A glass plate 0.9cm thick has a refractive index of 1.50. How long does it take for a pulse of light to pass through the plate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Refractive index; n = speed of light in air/speed of light in glass  <br/>  n= v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>/v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span>; 1.5 = 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>/v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span>  <br/>  v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span>= 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>/1.5 = 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m/s  <br/>  time required for a pulse of light to pass through = thickness(distance)/velocity= 0.9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>/2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>  <br/>  = 4.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>s</div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>2007>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental frequency of a plucked wire under a tension of 400N is 250 Hz. When the frequency is changed to 500 Hz at constant length, the tension is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">160N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">400N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1600N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tension, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>= 400N, f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>= 250Hz, f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= 500Hz  <br/>  The frequency of a plucked wire varies directly as the square root of its tension  <br/>  f α √ T, hence, f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 500<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 400/250<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 1600N</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2007>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The production of pure spectrum could easily be achieved using a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">triangular prism only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">triangular prism with two concave lenses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">triangular prism with two convex lenses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glass prism with a pin.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A pure spectrum constitute different colours that do not overlap. The colours must be clearly separated or distinct from each other. This can be produced using two converging lenses and a prism or two convex lenses and a prism.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : PRODUCTION OF PURE SPECTRUM"}, {"id": "objective>Physics>2007>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. They should be identical.  <br/>  II. They should originate from the same source.  <br/>  III. They should be coherent.  <br/>  IV. They should be monochromatic. From the statements above, the conditions for two waves to interfere are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II. III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Interference of two waves occurs when the two waves;  <br/>  I. Are identical  <br/> II. They should originate from the same source <br/>  III. They should be in the same direction or coherent.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2007>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The instrument used by designers to obtain different colour patterns is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">episcope </div>", "<div style=\"font-family:Cambria;font-size:17px;\">periscope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kaleiodoscope </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sextant</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kaleidoscope is used for this purpose. It works under the principle of inclination of two mirrors to produce multiple images.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2007>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an object is placed between the principal focus and the optical centre of a convex lens, it could be used as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflecting lens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compound microscope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">projector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">simple microscope</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A simple microscope is produced when an object is placed between the principal focus and the optical centre of a convex lens. This is the arrangement pattern in a simple microscope.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2007>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a large telecommunications auditorium, perforated absorbent materials are used to line the ceiling so as to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduce the reverberation of sound in the hall.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the height of the ceiling from the floor.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the reverberation of sound in the hall.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the amount of echo in the hall.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Perforated adsorbent materials are used to line the ceiling to prevent echo or reverberation of sound. If this done, it will prevent the collapsion of the building wall.</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2007>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon of light bending round an obstacle is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diffraction is a phenomenon whereby waves bend around around obstacles, it is also means the spreading of waves after passing through tiny aperture.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2007>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The energy E of a photon and its wavelength are related by Eλ = X. The numerical value of X is <br/>  <br/> [h = 6.63 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">34</span> Js, c = 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>].</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-27</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.60 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-26</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-25</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.60 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-25</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the equation; x = Eλ, we know that E = hf where  frequency, f= c/λ  <br/>  Hence x = hc/λ × λ = hc  <br/>  x = 6.63 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">34</span> Js × 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>= 1.99 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-25</span></div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2007>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A radioactive substance has a half-life of 20 days. What fraction of the original radioactive nuclei will remain after 80days?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/16 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/32</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a radioisotope decays, fraction remaining = Count rate at zero time/2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">N</span> <br/> Where N= no of half-life in a given time. In this case, N= 80 ÷ 20 = 4 <br/>  Hence remaining fraction = x/2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> = x/16 where x is the count rate at zero time.</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2007>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Silicon doped with aluminium and germanium doped with arsenic become</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">n-type semi-conductors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">p-type semi-conductors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n-and p-types respectively</div>", "<div style=\"font-family:Cambria;font-size:17px;\">p-and n-types respectively.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silicon has four electrons in its outermost shell. When it is doped with aluminium which has three electrons in its outermost shell, aluminium in this case is the impurity element. Hence we obtain a P-type semiconductor. For germanium doped with arsenic, an n-type semiconductor is obtained since germanium which is th semiconductor has four outermost electron while the impurity element; arsenic has five outermost electrons. </div>", "topic": "INTRODUCTORY ELECTRONICS : N-TYPE AND P-TYPE SEMI-CONDUCTORS"}, {"id": "objective>Physics>2007>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A photon of wavelength 6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> behaves like a particle of a certain mass. The value of that mass is ...... [h = 6.63 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js, c = 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-35</span> kg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-27</span> kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-36</span> kg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-35</span> kg</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">λ = 6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>m,  h = 6.63 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js, c = 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  <br/> Energy of photon, E= mc<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = hf, f = c/λ  <br/>  m = h/λc = 6.63 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>/[6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> × 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>] <br/>  m = 3.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-36</span> kg</div>", "topic": "ELEMENTARY MODERN PHYSICS : THERMIONIC AND PHOTOELECTRIC EMISSIONS"}, {"id": "objective>Physics>2007>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the nuclear reactions described by <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">235</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>W → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">235</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">93</span>X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">231</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">91</span>Y, the particles emitted are respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">β and β </div>", "<div style=\"font-family:Cambria;font-size:17px;\">β and α </div>", "<div style=\"font-family:Cambria;font-size:17px;\">α and β</div>", "<div style=\"font-family:Cambria;font-size:17px;\">α and α</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Beta emission involves atomic no increase by 1 while the mass no stays constant. <br/> Alpha emission on the other hand reduces atomic no by 2 and mass no by 4.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>2007>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bond that forms a semi-conductor is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ionic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrovalent</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Semiconductors are typically formed from elements in group 14 of the periodic table, such as silicon and germanium. These elements form covalent bonds with each other, sharing electrons to achieve a stable electron configuration. Therefore, the correct answer is option 3.</div>", "topic": "INTRODUCTORY ELECTRONICS"}, {"id": "objective>Physics>2007>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The instrument that measures both a.c. and d.c. is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an inverter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a current balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a moving coil ammeter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a moving iron ammeter</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A moving iron ammeter is an instrument that can measure both alternating current (a.c.) and direct current (d.c.). An inverter is a device that converts DC to AC. A current balance is a device used to measure magnetic field. A moving coil ammeter can only measure direct current.</div>", "topic": "MAGNETIC FIELD : MOVING COIL AND MOVING IRON INSTRUMENTS"}, {"id": "objective>Physics>2007>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lenz's law is a law of the conservation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">momentum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electric </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electric charge</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lenz's law illiustrates the principle of conservation of energy. The induced current sets up a force which opposes the motion of the magnet either when moving towards the coil or away from it. The mover of the magnet must overcome the force and the work done in overcoming the force supplies the electrical energy of the current, dissipated as heat in the coil.</div>", "topic": "ELECTROMAGNETIC INDUCTION : LENZ’S LAW"}, {"id": "objective>Physics>2007>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  Three cells each of e.m.f 1.5V and internal resistance 2.5Ω are connected as shown in the diagram above. Find the net e.m.f. and the internal resistance.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.5V, 7.50Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5V, 0.83Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5V, 7.50Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5V, 0.83Ω</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The net emf for circuit in parallel is the respective emf while resistance is the effective resistance of parallel connection.  <br/>  1/r = 1/r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+1/r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>+1/r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>  <br/>  1/r = 3/2.5 ; hence, r= 2.5/3 = 0.83Ω.</div>", "topic": "ELECTRIC CELLS : ARRANGEMENT OF CELLS"}, {"id": "objective>Physics>2007>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 120V, 60W lamp is to be operated on 220V a.c. supply mains. Calculate the <br/> value of non-inductive resistance that would be required to ensure that the <br/> lamp is run on correct value.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">440Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">300Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">200Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">100Ω</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P= IV therefore I=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">P</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">V</span> <br/>  <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">lamp</span>= 60W         Vlamp=120W <br/>  <br/> I= <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">60</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">120</span>  = 0.5A <br/>  <br/> R=V/I <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">mains</span>=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">220</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0.5</span> =440Ω <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">lamp</span>= <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">120</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0.5</span>= 240Ω <br/>  <br/> Non inductive resistance = 440-240=200Ω</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2007>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, if the magnetic field points into the paper and the force on a current-carrying conductor points upwards, what is the direction of the current?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Downwards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Left </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Upward.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The direction of the current would be to the left.</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2007>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The instantaneous value of the induced e.m.f. as a function of time is ε = εo sinwt where εo is the peak value of the e.m.f. The instantaneous value of the e.m.f, one quarter of the period, is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">εo </div>", "<div style=\"font-family:Cambria;font-size:17px;\">εo/2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">εo/4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">eriod = 1 cycle of 360 <br/> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span> of T = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span> of 360  <br/>  = 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> <br/> E = εsinwt <br/> E = ε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>sin90 <br/> sin 90 = 1 <br/> E = ε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></div>", "topic": "ELECTROMAGNETIC INDUCTION"}, {"id": "objective>Physics>2007>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">118.8 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> surface of the copper cathode of a voltameter is to be coated with 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m thick copper of density 9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. How long will the process run with 10A constant current? [e.c.e. of copper = 3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> kg C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.8 min </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0 min.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.54 min. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.0 min.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">m = ZIt, t = m/ZI. mass, m= density × volume  <br/>  volume= area × thickness = 118.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>× 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>= 1.188 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  m = 9 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>×1.188 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>= 1.0692 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>Kg  <br/>  t = 1.0692 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>/[3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> kg C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>× 10] = 32.4s = 0.54min</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2007>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A conductor has a diameter of 1.00mm and length 2.00m. If the resistance of the material is 0.1Ω, its resistivity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span> Ωm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> Ωm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.55 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> Ωm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.55 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> Ωm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R= ρl/A  where ρ= resistivity, l=length, A= area  <br/>  A= πd<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/4 = π × (1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>)/4 = 7.855 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/>  ρ = RA/l = 0.1 × 7.855 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>/2 = 3.93 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>Ωm <br/> </div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2007>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A charge 50μC has an electric field strength of 360 NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at a certain point. The electric field strength due to another charge 120μC. kept at the same distance apart and in the same medium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18 NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">144 NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">150 NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">864 NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Electric</td><td style=\"text-align:center;\">field</td><td style=\"text-align:center;\">strength,</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">force<hr size=\"1\" />charge</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />Q</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">q<hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">⇒</td><td style=\"text-align:center;\">360</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span> × 50 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> Solving for r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>: <br/>  <br/> ⇒ r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 1250 m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  <br/> So, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span> × 120 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span><hr size=\"1\" />1250</td></tr></table></div> <br/> E = 864 NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2007>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two long parallel wires X and Y carry currents 3A and 5A respectively. If the force experienced per unit length by X is 5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>N, the force per unit length experienced by wire Y is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F = ILBsin θ Since the wires are parallel, resultant force = zero  <br/>  This would mean that the force on Y ia equal to that on X = 5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>N</div>", "topic": "MAGNETIC FIELD : FORCE ON A CURRENT-CARRYING CONDUCTOR"}, {"id": "objective>Physics>2007>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram, the inductive reactance and the resistance R are respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10Ω and 50Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20Ω and 50Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25Ω and 50Ω </div>", "<div style=\"font-family:Cambria;font-size:17px;\">50Ω and 45Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 2 πfL = inductance reactance  <br/>  X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>= 2π × 50/π × 0.1 = 10Ω  <br/>  Resistance, R = V/I = 75 ÷ 1.5 = 50  <br/>  X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>= 10Ω, R = 50Ω</div>", "topic": "SIMPLE A. C. CIRCUITS : INDUCTOR - INDUCTIVE REACTANCE"}, {"id": "objective>Physics>2007>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 40kW electric cable is used to transmit electricity through a resistor of <br/> resistance 2.0Ω at 800V. The power loss as internal energy is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>W </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>W </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>W</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Power rating= 40kW = 40,000W = I × V  <br/>  I= 40,000/800 = 50A.  <br/>  Hence power loss = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>r = 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>× 2 = 5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>W </div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2007>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If two charged plates are maintained at a potential difference of 3 kV, the work done in taking a charge of 600μC across the field is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9.0J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">18.0J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P.D = work done per unit charge  <br/>  W = Potential difference × charge = QV = 3000 × 600 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>  <br/>  = 1.8J</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2007>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ratio of the coefficient of linear expansion of two metals α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is 3:4. If, when heated through the same temperature change, the ratio of the increase in length of the two metals, e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is 1 : 2, the ratio of the original length l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2/3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8/3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3/8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3/2</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= 3/4 , e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= 1/2  l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= ? Change in length, e = αlθ where α = linear expansivity, θ = change in temperature  <br/>  e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>θ .....(1)  <br/>  e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>θ .....(2) Dividing equation 1 by 2  <br/>  1/2 = 3/4 × l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  Hence, l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 4/6 = 2/3</div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2007>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Mass  <br/>  II. Density  <br/>  III. Temperature  <br/>  IV. Nature of substance  <br/>  Which of the above affect diffusion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion is the process of spread of particles from a region of higher concentration to a region of lower concentration. It is affected by the density of the substance (the denser the substance, the slower the diffusion), the temperature (the higher the temperature, the faster the diffusion), and the nature of the substance (different substances diffuse at different rates). Therefore, the correct answer is II, III and IV only.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2007>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A string of length 4m is extended by 0.02m when a load of 0.4 kg is suspended at its end. What will be the length of the string when the applied force is 15N? [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>].</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.05m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.08m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.05m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.08m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">W = mg = 0.4 × 10 = 4N  <br/>  W = F = Ke; W α e  <br/>  W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  4/0.02 = 15/e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.02 × 15/4 = 0.075m. <br/> 4m + 0.075 <br/>  = 4.075 <br/> ≃ 4.08 <br/> </div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2007>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Use a liquid with a high melting point <br/> II. Use a liquid of high volume expansivity <br/> III. Use a capillary tube of large diameter. <br/> Which of the above best describes how the sensitivity of a liquid-in-glass thermometer can be enhanced?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To improve the sensitivity of a liquid-in-glass thermometer, use a liquid with a high volume expansivity. This means the liquid expands significantly when heated, resulting in a larger change in the liquid level within the capillary tube, making the thermometer more responsive to temperature variations.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2007>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The blade of a hoe feels colder to touch in the morning than the wooden handle <br/> because the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">handle contains stored energy in form of heat.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blade is placed at a lower temperature than the handle.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">handle is a better conductor of heat than the blade.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blade is a better conductor of heat than the handle.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The blade of a hoe feels colder to touch in the morning than the wooden handle because the blade is a better conductor of heat than the handle. When you touch the blade, it conducts heat away from your hand faster than the wooden handle, making it feel colder. This is a property of metals, which are generally good conductors of heat.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2007>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gas laws is equivalent to the work done?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pressure Law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Van der Waal's Law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Boyle's Law </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Charles' Law</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The work done in a gas system is equivalent to Boyle's Law. Boyle's Law states that the pressure and volume of a gas have an inverse relationship when temperature is held constant. In other words, when the volume of a gas increases, the pressure decreases and vice versa. This is similar to the concept of work done, where work is the result of a force causing displacement. In the case of a gas system, the force is the pressure and the displacement is the change in volume.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2007>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of iron weighs 250N in air and 200N in a liquid of density 1000 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. The volume of the iron is [g = 10ms-2]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Volume = mass/density  <br/>  The volume displaced in a liquid is the volume of the iron  <br/>  Weight displaced = W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">air</span> - W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">liquid</span> = 250N - 200N = 50N  <br/>  W= mg; m = weight/gravity = 50/10 = 5Kg  <br/>  Volume = mass/density = 5/1000 = 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>.</div>", "topic": "LIQUIDS AT REST : ARCHIMEDE’S PRINCIPLE"}, {"id": "objective>Physics>2007>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Increase the melting point of the liquid.  <br/>  II. Increase the boiling point of the liquid.  <br/>  III. decrease the melting point of the liquid.  <br/>  IV. decrease the boiling point of the liquid.  <br/>  <br/>  Which of the statements above about the effects of increase in pressure in a liquid are correct, if the liquid is water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Melting Point of Water:</strong> <br/>  <br/> Unlike most substances, increasing pressure on ice (solid water) actually decreases its melting point. This is a unique property of water due to its molecular structure and the fact that ice is less dense than liquid water. As pressure increases, it favors the denser phase, which is liquid water, causing the ice to melt at a lower temperature.    <br/>  <br/> Therefore, for water, an increase in pressure will: <br/>  <br/> III. decrease the melting point of the liquid. - This statement is correct for water. <br/> I. Increase the melting point of the liquid. - This statement is incorrect for water. <br/>  <br/> <strong>Boiling Point of Water:</strong> <br/>  <br/> Similar to other liquids, increasing the pressure on water increases its boiling point. Higher pressure makes it more difficult for water molecules to escape into the gaseous phase, requiring a higher temperature for boiling to occur. This is why pressure cookers can heat water to temperatures above 100°C.    <br/>  <br/> Therefore, for water, an increase in pressure will: <br/>  <br/> II. Increase the boiling point of the liquid. - This statement is correct for water. <br/> IV. Decrease the boiling point of the liquid. - This statement is incorrect for water. <br/> So, if the liquid is water, the correct statements about the effects of an increase in pressure are II and III. <br/>  <br/> Therefore, the correct option is II and III only.</div>", "topic": "CHANGE OF STATE : EFFECT OF PRESSURE AND IMPURITIES ON BOILING AND MELTING POINTS"}, {"id": "objective>Physics>2007>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A blacksmith heated a metal whose cubic expansivity is 6.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The area expansivity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Area expensivity, β = 2α where α = linear expansivity  <br/>  Cubic expansivity; γ = 3 α  <br/>  β = 2 × γ/3 = 2/3 × 6.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = 4.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "HEAT TRANSFER~~HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2007>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The differences observed in solids, liquids and gases may be accounted for by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">their relative masses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their melting points</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the different molecules in each of them.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the spacing and forces acting between the molecules.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For solids , the intermolecular distance are small and forces of intermolecular attraction are large , for liquid the molecules are further apart than solids hence have larger molecular distance , for gases the intermolecular distance are larger than that f solid and liquid and the forces of intermolecular attraction are negligible  </div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2007>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A reservoir 500m deep is filled with a fluid of density 850kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. If the atmospheric pressure is 1.05 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, the pressure at the bottom of the reservoir is [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.36 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.72 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.28 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure at the bottom = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> + ρhg  <br/>  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>= atmospheric pressure v ρhg = pressure due to height below liquid  <br/>  P= 1.05 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> × 850 × 10 × 500 = 4.36 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> </div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE~~PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2007>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A clinical thermometer is different from other mercury in glass thermometers <br/> owing to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its long stem.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the constriction on its stem.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its wide range of temperature.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the grade of mercury used in it.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A clinical thermometer is different from other mercury in glass thermometers due to the constriction on its stem. The constriction prevents the mercury level from falling on its own, which allows the temperature to be read long after the thermometer has been removed from the patient.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2007>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2kg of water is heated with a heating coil which draws 3.5A from a 200V mains for 2 minutes. What is the increase in temperature of the water? [c=4200J/KgK</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat required to increase the temperature of the water = mcθ, is provided by the heating coil  <br/>  The energy supplied = IVt = 3.5 × 200 × 2 × 60 = 8400J  <br/>  c = 4200J/kgk, θ = 8400/2 × 4200 = 10°C.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2007>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boy drags a bag of rice along a smooth horizontal floor with a force of 2N applied at an angle of 60° to the floor. The work done after a distance of 3m is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4J </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Workdone at angle θ = Fdcosθ  <br/>  = 2 × 3 × cos60  <br/> = 3J.</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2007>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The figure above shows 4 forces 3N,10N, 3 √ 3N and 6N acting on a particle P. The resultant of the four forces is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10√3 N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 √3 N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5N.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">3Ncos0 = 3N <br/> 10cos 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = 8.7N <br/> 3&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>cos 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = 0N <br/> -6cos60 = -3N <br/> Efx = 8.7N <br/>  y - axis <br/> 3Nsin0 = 0 <br/> 10sin30 = 5N <br/> 3*&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>sin90 = 5.2N <br/> -6sin60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = -5.2N <br/> Efy = 5N <br/> R = sqr(5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>+8.7<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> The resultant force is 10N.</div>", "topic": "EQUILIBRIUM OF FORCES : EQUILIBRIUM OF PARTICLES"}, {"id": "objective>Physics>2007>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two spheres of masses 5.0 kg and 10.0kg are 0.3m apart. Calculate the force of attraction between them. [G = 6.67 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>] <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.71 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.57 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>N <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The force of attraction between two masses can be calculated using Newton's law of universal gravitation. The formula is F = G * (m1 * m2) / r^2, where F is the force of attraction between the masses, G is the gravitational constant, m1 and m2 are the two masses, and r is the distance between the centers of the two masses.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2007>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car of mass 1500 kg goes round a circular curve of radius 50m at a speed of 40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The magnitude of the centripetal force on the car is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The magnitude of the centripetal force on a body moving in a circular path is given by the formula F = m * v^2 / r, where F is the centripetal force, m is the mass of the body, v is the velocity of the body, and r is the radius of the circular path.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2007>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The unit of moment of a couple can be expressed in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unit of moment of a couple is Newton meter (Nm). A moment of a couple is the product of the force and the distance between the forces, which results in the unit Nm.</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2007>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine has a velocity ratio of 4. If it requires 800N to overcome a load of <br/> 1600N, what is the efficiency of the machine?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">40% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">50% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">60%.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The efficiency of a machine is given by the ratio of the useful work done (load) to the work done on the machine (effort). In this case, the load is 1600N and the effort is 800N. Therefore, the efficiency is (1600/800) * 100 = 50%. The concept here is the efficiency of a machine, which is a measure of how much of the work put into a machine is converted into useful output.</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2007>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, a rod 50cm long of uniform cross-section is suspended horizontally on a fulcrum, F, by the action of the forces. What is the weight of the rod?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">120N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">200N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">40N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">80N.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let W = weight of the road. The weight of the rod is assumed to be on the right side of the fulcrum. <br/>  Taking moment about the pivot; 200 × 10 = W × 10 + 40 × 30  <br/>  W = (2000-1200)/10 = 80N.</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2007>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gramophone record takes 5s to reach its constant angular velocity of 4π <br/> rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> from rest. Find its constant angular acceleration.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20.0π rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.3π rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8π rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4π rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Angular acceleration; α = Ω/t = 4π/5 = 0.8π rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2007>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle of weight 120N is placed on a plane inclined at an angle 30° to the horizontal. If the plane has an efficiency of 60%, what is the force required to push the weight uniformly up the plane?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">210N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">175N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">100N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">50N.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Velocity ratio of an inclined plane =1/sinθ = 1/sin30° =1/0.5 = 2  <br/>  Efficiency = M.A/V.R; M.A = 0.6 × 2 = 1.2  <br/>  Since M.A = load/effort, the required force to push the weight up = 120/1.2 = 100N.</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2007>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram above, the bob of the pendulum has the fastest speed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">W </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pendulum will have its fastest speed at the point X.</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}];
